    <Card className="w-full max-w-4xl shadow-xl hover:shadow-lg transiton-all duration-300">
      <CardHeader>
        <CardTitle>{title}</CardTitle>
        <CardDescription >{description}</CardDescription>
      </CardHeader>
      <CardContent>
