"use client";

import * as React from "react";
import * as SubframeCore from "@subframe/core";

/**
 * IMPORTANT: Local SubframeUtils lives INSIDE this component file.
 * Provides createTwClassNames() and twClassNames instance.
 */
namespace SubframeUtils {
  export type ClassValue =
    | string
    | null
    | undefined
    | false
    | Record<string, boolean>;

  export function createTwClassNames() {
    return (...classes: ClassValue[]) =>
      classes
        .flatMap((c) => {
          if (!c) return [];
          if (typeof c === "string") return [c];
          return Object.entries(c)
            .filter(([, ok]) => !!ok)
            .map(([k]) => k);
        })
        .join(" ");
  }

  export const twClassNames = createTwClassNames();
}

export interface ComponentProps extends React.HTMLAttributes<HTMLDivElement> {
  variant?: "brand" | "neutral" | "error" | "warning" | "success";
  icon?: React.ReactNode;
  children?: React.ReactNode;
  iconRight?: React.ReactNode;
  className?: string;
}

/**
 * Variant B: self-contained Tailwind colors (no custom token dependency)
 */
const VARIANT_STYLES: Record<
  NonNullable<ComponentProps["variant"]>,
  { container: string; text: string; icon: string }
> = {
  brand: {
    container: "border-indigo-100 bg-indigo-100",
    text: "text-indigo-800",
    icon: "text-indigo-700",
  },
  neutral: {
    container: "border-zinc-200 bg-zinc-100",
    text: "text-zinc-800",
    icon: "text-zinc-700",
  },
  success: {
    container: "border-green-100 bg-green-100",
    text: "text-green-800",
    icon: "text-green-800",
  },
  warning: {
    container: "border-amber-100 bg-amber-100",
    text: "text-amber-800",
    icon: "text-amber-800",
  },
  error: {
    container: "border-red-100 bg-red-100",
    text: "text-red-800",
    icon: "text-red-700",
  },
};

export const Component = React.forwardRef<HTMLDivElement, ComponentProps>(
  function Component(
    { variant = "brand", icon = null, children, iconRight = null, className, ...otherProps },
    ref
  ) {
    const v = VARIANT_STYLES[variant];

    return (
      <div
        ref={ref}
        {...otherProps}
        className={SubframeUtils.twClassNames(
          // base
          "flex h-6 items-center gap-1 rounded-md border px-2",
          // variant
          v.container,
          className
        )}
      >
        {icon ? (
          <SubframeCore.IconWrapper
            className={SubframeUtils.twClassNames("text-caption font-caption", v.icon)}
          >
            {icon}
          </SubframeCore.IconWrapper>
        ) : null}

        {children ? (
          <span
            className={SubframeUtils.twClassNames(
              "whitespace-nowrap text-caption font-caption",
              v.text
            )}
          >
            {children}
          </span>
        ) : null}

        {iconRight ? (
          <SubframeCore.IconWrapper
            className={SubframeUtils.twClassNames("text-caption font-caption", v.icon)}
          >
            {iconRight}
          </SubframeCore.IconWrapper>
        ) : null}
      </div>
    );
  }
);

// Named + default export
export default Component;


