import React, {
  useEffect,
  useId,
  useMemo,
  useRef,
  useState,
  useCallback,
} from "react";

/**
 * ===================================
 * Types & Interfaces
 * ===================================
 */
export type SidebarLink = {
  id: string;
  label: string;
  href?: string;
  icon?: React.ReactNode;
  active?: boolean;
};

export type Stat = {
  id: string;
  label: string;
  value: number | string;
};

export type ProjectStatus = "inProgress" | "upcoming" | "completed" | "paused";

export type Project = {
  id: string;
  name: string;
  subtitle?: string;
  date?: string;
  progress?: number;
  status?: ProjectStatus;
  accentColor?: string;
  participants?: string[];
  daysLeft?: number | string;
  bgColorClass?: string;
};

export type Message = {
  id: string;
  name: string;
  avatarUrl: string;
  text: string;
  date: string;
  starred?: boolean;
};

export type SortBy = "manual" | "date" | "name" | "progress";
export type SortDir = "asc" | "desc";
export type ThemeMode = "light" | "dark" | "system";

export type ProjectDashboardProps = {
  title?: string;
  user?: { name?: string; avatarUrl?: string };
  sidebarLinks?: SidebarLink[];
  stats?: Stat[];
  projects: Project[];
  messages?: Message[];
  view?: "grid" | "list";
  defaultView?: "grid" | "list";
  onViewChange?: (view: "grid" | "list") => void;
  searchQuery?: string;
  defaultSearchQuery?: string;
  onSearchQueryChange?: (q: string) => void;
  showSearch?: boolean;
  searchPlaceholder?: string;
  messagesOpen?: boolean;
  defaultMessagesOpen?: boolean;
  onMessagesOpenChange?: (open: boolean) => void;
  sortBy?: SortBy;
  defaultSortBy?: SortBy;
  sortDir?: SortDir;
  defaultSortDir?: SortDir;
  onSortChange?: (by: SortBy, dir: SortDir) => void;
  statusFilter?: ProjectStatus | "all";
  defaultStatusFilter?: ProjectStatus | "all";
  onStatusFilterChange?: (status: ProjectStatus | "all") => void;
  pageSize?: number;
  initialPage?: number;
  onPageChange?: (page: number) => void;
  virtualizeList?: boolean;
  estimatedRowHeight?: number;
  onProjectClick?: (projectId: string) => void;
  onProjectAction?: (projectId: string, action: "open" | "edit" | "delete") => void;
  onProjectUpdate?: (project: Project) => void;
  onProjectsReorder?: (orderedIds: string[]) => void;
  allowCreate?: boolean;
  onProjectCreate?: (project: Project) => void;
  generateId?: () => string;
  onMessageStarChange?: (messageId: string, starred: boolean) => void;
  showThemeToggle?: boolean;
  onToggleTheme?: () => void;
  theme?: ThemeMode;
  defaultTheme?: ThemeMode;
  onThemeChange?: (mode: ThemeMode) => void;
  persistKey?: string;
  className?: string;
  loading?: boolean;
  emptyProjectsLabel?: string;
  emptyMessagesLabel?: string;
};

/**
 * ===================================
 * Spacing System - Consistent padding/margins
 * ===================================
 */
const spacing = {
  page: {
    header: "px-4 sm:px-6 lg:px-8 py-4",
    sidebar: "px-2 sm:px-3 py-4",
    main: "px-4 sm:px-6 lg:px-8 py-4",
    messages: "px-4 sm:px-6 py-4"
  },
  card: {
    base: "p-4 sm:p-5 lg:p-6",
    compact: "p-3 sm:p-4"
  },
  button: {
    sm: "px-2.5 py-1.5",
    md: "px-3 py-2",
    lg: "px-4 py-2.5"
  },
  gap: {
    xs: "gap-2",
    sm: "gap-3",
    md: "gap-4",
    lg: "gap-6"
  }
};

/**
 * ===================================
 * Utilities
 * ===================================
 */
const cx = (...classes: Array<string | false | null | undefined>) => {
  return classes.filter(Boolean).join(" ");
};

const parseDateLike = (v?: string): number => {
  if (!v) return 0;
  const ts = Date.parse(v);
  return Number.isNaN(ts) ? 0 : ts;
};

const clamp = (n: number, min: number, max: number) => {
  return Math.min(Math.max(n, min), max);
};

const readLS = <T,>(key: string, fallback: T): T => {
  try {
    const raw = localStorage.getItem(key);
    return raw ? (JSON.parse(raw) as T) : fallback;
  } catch {
    return fallback;
  }
};

const writeLS = <T,>(key: string, value: T) => {
  try {
    localStorage.setItem(key, JSON.stringify(value));
  } catch {}
};

/**
